#include<bits/stdc++.h>
using namespace std;
long long dis[100010];
bool vis[100010];
vector<pair<long long,long long>> mp[100010];
void dijkstra(long long x)
{
    memset(vis,0,sizeof(vis));
    memset(dis,0x3f,sizeof(dis));
    dis[x]=0;
    priority_queue<pair<long long,long long>> q;
    q.push(make_pair(0ll,x));
    while(!q.empty())
    {
        long long t=q.top().second;
        q.pop();
        if(vis[t])
        {
            continue;
        }
        vis[t]=1;
        for(auto i:mp[t])
        {
            long long v=i.first,val=i.second;
            if(dis[v]>dis[t]+val)
            {
                dis[v]=dis[t]+val;
                q.push(make_pair(-dis[v],v));
            }
        }
    }
}
int main()
{
    long long h,x,y,z;
    scanf("%lld%lld%lld%lld",&h,&x,&y,&z);
    h--;
    for(long long i=0;i<x;i++)
    {
        mp[i].push_back(make_pair((i+y)%x,y));
        mp[i].push_back(make_pair((i+z)%x,z));
    }
    dijkstra(0);
    long long ans=0;
    for(long long i=0;i<x;i++)
    {
        if(dis[i]<=h)
        {
            ans+=(h-dis[i])/x+1;
        }
    }
    printf("%lld",ans);
    return 0;
}
